#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, b;
        scanf("%d %d", &n, &b);
        if (b <= n - 1) {
            printf("YES\n");
            for (int i = 2; i <= n; i++) {
                printf("1 %d\n", i);
            }
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

