import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int b = sc.nextInt();
            if (b <= n - 1) {
                System.out.println("YES");
                for (int i = 2; i <= n; i++) {
                    System.out.println(1 + " " + i);
                }
            } else {
                System.out.println("NO");
            }
        }
    }
}

